<template>
  <div class="onboarding-container">
    <div class="header">
      <div class="logo">
        <img src="/favicon.ico" alt="Pomelo" class="logo-img">
        <span class="logo-text">西柚 Pomelo</span>
      </div>
      <h2>Merchant Onboarding</h2>
      <p>Complete the form to join our platform</p>
    </div>
    
    <ProgressBar currentStep="1" />
    
    <div class="form-section">
      <h3>Business Information</h3>
      <p class="section-desc">Please fill in the basic information of your business</p>
      
      <el-form ref="form" :model="form" :rules="rules" label-width="180px">
        <el-form-item label="Business Name *" prop="merchantName">
          <el-input v-model="form.merchantName" placeholder="Enter your business name" maxlength="80"/>
        </el-form-item>
        <el-form-item label="Business English Name" prop="merchantEnName">
          <el-input v-model="form.merchantEnName" placeholder="English name optional" maxlength="80"/>
        </el-form-item>
        <el-form-item label="Business Introduction" prop="merchantDesc">
          <el-input v-model="form.merchantDesc" type="textarea" placeholder="Brief description of your products or services" maxlength="300"/>
        </el-form-item>
        
        <div class="upload-section">
          <div class="upload-item">
            <label>Business Logo</label>
            <div class="upload-box">
              <BigFileUpload 
                @handleUploadSuccess="handleUploadSuccess"
                :defaultUrl = "form.logo"
                :imgWidth="138"
                :imgHeight="138"
                :flag="1"
                :isOnlyShow="false"
              />
              <p class="upload-hint">PNG, JPG, JPEG, up to 5MB</p>
            </div>
          </div>
          <div class="upload-item">
            <label>Shop Picture</label>
            <div class="upload-box">
              <BigFileUpload 
                @handleUploadSuccess="handleUploadSuccess"
                :defaultUrl = "form.shopImg"
                :imgWidth="200"
                :imgHeight="138"
                :flag="2"
                :isOnlyShow="false"
              />
              <p class="upload-hint">PNG, JPG, JPEG, up to 5MB</p>
            </div>
          </div>
        </div>
        
        <div class="form-buttons">
          <el-button class="save-draft-btn" @click="saveDraft">Save Draft</el-button>
          <el-button class="next-btn" type="primary" @click="nextStep">Next ></el-button>
        </div>
      </el-form>
    </div>
    
    <div class="footer-note">
      <p>Your information is secure and will only be used for merchant verification.</p>
    </div>
  </div>
</template>

<script>
/* eslint-disable vue/multi-word-component-names */
import BigFileUpload from '@/components/BigFileUpload.vue'
import ProgressBar from '@/components/ProgressBar.vue'

export default {
  name: 'BusinessInfo',
  components: {
    BigFileUpload,
    ProgressBar
  },
  data() {
    return {
      form: {
        merchantName: '',
        merchantEnName: '',
        merchantDesc: '',
        logo: '',
        shopImg: ''
      },
      rules: {
        merchantName: [
          { required: true, message: "Please input business name", trigger: "blur" }
        ]
      }
    }
  },
  methods: {
    saveDraft() {
      this.$message.success('Draft saved successfully!');
    },
    nextStep() {
      this.$refs["form"].validate((valid) => {
        if (valid) {
          // 保存当前表单数据到sessionStorage
          sessionStorage.setItem('businessInfo', JSON.stringify(this.form));
          // 跳转到下一步
          this.$router.push('/service');
        }
      });
    },
    handleUploadSuccess(response, flag) {
      // 处理文件上传成功的回调
      console.log('File uploaded successfully:', response, flag);
      switch(flag) {
        case 1:
          this.form.logo = response.url || response.path || response;
          break;
        case 2:
          this.form.shopImg = response.url || response.path || response;
          break;
      }
    }
  },
  mounted() {
    // 从sessionStorage加载数据
    const savedData = sessionStorage.getItem('businessInfo');
    if (savedData) {
      this.form = JSON.parse(savedData);
    }
  }
}
</script>

